"""Error hierarchy for queryweave."""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any


@dataclass
class ErrorContext:
    """Structured context attached to any queryweave error."""

    message: str
    table: str | None = None
    column: str | None = None
    line: int | None = None
    col: int | None = None
    value: Any = None
    details: dict[str, Any] = field(default_factory=dict)

    def __str__(self) -> str:
        parts = [self.message]
        if self.table:
            parts.append(f"table={self.table}")
        if self.column:
            parts.append(f"column={self.column}")
        if self.line is not None:
            loc = f"line {self.line}"
            if self.col is not None:
                loc += f", col {self.col}"
            parts.append(loc)
        if self.value is not None:
            parts.append(f"value={self.value!r}")
        return " | ".join(parts)


class QueryWeaveError(Exception):
    """Base for all queryweave errors."""

    def __init__(self, message: str, ctx: ErrorContext | None = None) -> None:
        self.ctx = ctx or ErrorContext(message=message)
        super().__init__(str(self.ctx))

    @property
    def table(self) -> str | None:
        return self.ctx.table

    @property
    def column(self) -> str | None:
        return self.ctx.column


class ParseError(QueryWeaveError):
    """Raised when SQL parsing fails."""

    def __init__(
        self,
        message: str,
        line: int | None = None,
        col: int | None = None,
        snippet: str | None = None,
    ) -> None:
        ctx = ErrorContext(message=message, line=line, col=col)
        if snippet:
            ctx.details["snippet"] = snippet
        super().__init__(message, ctx)

    @property
    def location(self) -> str:
        if self.ctx.line is None:
            return "unknown"
        s = f"line {self.ctx.line}"
        if self.ctx.col is not None:
            s += f":{self.ctx.col}"
        return s


class QueryTypeError(QueryWeaveError):
    """Raised on type mismatch in expressions or comparisons."""

    def __init__(
        self,
        message: str,
        expected: str | None = None,
        got: str | None = None,
        column: str | None = None,
    ) -> None:
        ctx = ErrorContext(message=message, column=column)
        if expected:
            ctx.details["expected"] = expected
        if got:
            ctx.details["got"] = got
        super().__init__(message, ctx)


class ExecutionError(QueryWeaveError):
    """Raised during query execution."""

    def __init__(
        self,
        message: str,
        table: str | None = None,
        column: str | None = None,
        operation: str | None = None,
    ) -> None:
        ctx = ErrorContext(message=message, table=table, column=column)
        if operation:
            ctx.details["operation"] = operation
        super().__init__(message, ctx)


class CatalogError(QueryWeaveError):
    """Raised for catalog/registry operations."""

    def __init__(self, message: str, table: str | None = None) -> None:
        super().__init__(message, ErrorContext(message=message, table=table))


class ConstraintViolation(QueryWeaveError):
    """Raised when a constraint check fails."""

    def __init__(
        self,
        message: str,
        constraint_type: str,
        table: str | None = None,
        column: str | None = None,
        value: Any = None,
    ) -> None:
        ctx = ErrorContext(
            message=message, table=table, column=column, value=value,
        )
        ctx.details["constraint_type"] = constraint_type
        self.constraint_type = constraint_type
        super().__init__(message, ctx)


class QueryIndexError(QueryWeaveError):
    """Raised for index-related failures."""

    def __init__(
        self,
        message: str,
        table: str | None = None,
        column: str | None = None,
        index_name: str | None = None,
    ) -> None:
        ctx = ErrorContext(message=message, table=table, column=column)
        if index_name:
            ctx.details["index_name"] = index_name
        super().__init__(message, ctx)


class IOError_(QueryWeaveError):
    """Raised for import/export failures."""

    def __init__(self, message: str, path: str | None = None) -> None:
        ctx = ErrorContext(message=message)
        if path:
            ctx.details["path"] = path
        super().__init__(message, ctx)


def format_error_for_display(err: QueryWeaveError) -> str:
    """Format an error for user-facing display."""
    prefix = type(err).__name__
    lines = [f"ERROR ({prefix}): {err.ctx.message}"]

    if isinstance(err, ParseError) and err.ctx.line is not None:
        lines.append(f"  at {err.location}")
        snippet = err.ctx.details.get("snippet")
        if snippet:
            lines.append(f"  near: {snippet}")

    if isinstance(err, ConstraintViolation):
        lines.append(f"  constraint: {err.constraint_type}")

    if err.ctx.table:
        lines.append(f"  table: {err.ctx.table}")
    if err.ctx.column:
        lines.append(f"  column: {err.ctx.column}")
    if err.ctx.value is not None:
        lines.append(f"  value: {err.ctx.value!r}")

    return "\n".join(lines)

